const h = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const token = h['x-meta-token'];
const account = h['x-meta-account'];
if (!token) {
  $execution.abort({ message: 'Missing Meta token' });
}
const allowedActions = ['pause', 'enable', 'scale_budget'];
const action = allowedActions.includes(body.action) ? body.action : null;
if (!action) {
  $execution.abort({ message: 'Invalid action. Use: pause, enable, or scale_budget' });
}
const ids = Array.isArray(body.campaign_ids) ? body.campaign_ids.slice(0, 50) : [];
if (!ids.length) {
  $execution.abort({ message: 'campaign_ids must be a non-empty array (max 50)' });
}
const multiplier = Math.min(2.0, Math.max(1.01, parseFloat(body.budget_multiplier) || 1.15));
return [{ json: { token, account, action, ids, multiplier } }];

const { token, account, action, ids, multiplier } = $input.item.json;
const GRAPH = 'https://graph.facebook.com/v19.0';
const results = [];
const errors = [];

for (const id of ids) {
  try {
    let body;
    if (action === 'pause') {
      body = { status: 'PAUSED', access_token: token };
    } else if (action === 'enable') {
      body = { status: 'ACTIVE', access_token: token };
    } else if (action === 'scale_budget') {
      // First fetch current budget
      const infoRes = await fetch(`${GRAPH}/${id}?fields=daily_budget,lifetime_budget&access_token=${token}`);
      const info = await infoRes.json();
      if (info.daily_budget) {
        body = { daily_budget: Math.round(parseInt(info.daily_budget) * multiplier), access_token: token };
      } else if (info.lifetime_budget) {
        body = { lifetime_budget: Math.round(parseInt(info.lifetime_budget) * multiplier), access_token: token };
      } else {
        errors.push({ id, error: 'No budget found' });
        continue;
      }
    }
    const res = await fetch(`${GRAPH}/${id}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    const data = await res.json();
    if (data.error) {
      errors.push({ id, error: data.error.message });
    } else {
      results.push({ id, success: true });
    }
  } catch(e) {
    errors.push({ id, error: e.message || 'Request failed' });
  }
}

return [{ json: {
  action,
  total: ids.length,
  succeeded: results.length,
  failed: errors.length,
  errors: errors.slice(0, 10),
  message: `${action} applied to ${results.length} of ${ids.length} campaign${ids.length > 1 ? 's' : ''}`
} }];
